local function startFreecamLoop() RS:BindToRenderStep("XKIDFreecam",Enum.RenderPriority.Camera.Value+1,function(dt) if not FC.active then return end; Cam.CameraType=Enum.CameraType.Scriptable; local sdt=math.clamp(dt,0.001,0.05); I_YawVel=I_YawVel*math.max(0,1-sdt*14); I_PitchVel=I_PitchVel*math.max(0,1-sdt*14); FC.yawDeg=FC.yawDeg+I_YawVel*sdt; FC.pitchDeg=math.clamp(FC.pitchDeg+I_PitchVel*sdt,-80,80); local rT=0; if FC_UI_Btns.rollLeft then rT=-100 elseif FC_UI_Btns.rollRight then rT=100 end; I_RollVel=I_RollVel+(rT-I_RollVel)*math.clamp(sdt*5,0,1); FC.rollDeg=math.clamp(FC.rollDeg+I_RollVel*sdt,-100,100); local camCF=CFrame.new(FC.pos)*CFrame.Angles(0,math.rad(FC.yawDeg),0)*CFrame.Angles(math.rad(FC.pitchDeg),0,0); local jX,jY=fcJoy.X,fcJoy.Y; if not onMobile then if fcKeysHeld[Enum.KeyCode.W] then jY=jY-1 end; if fcKeysHeld[Enum.KeyCode.S] then jY=jY+1 end; if fcKeysHeld[Enum.KeyCode.D] then jX=jX+1 end; if fcKeysHeld[Enum.KeyCode.A] then jX=jX-1 end end; local rMove=Vector2.new(jX,jY); if rMove.Magnitude>1 then rMove=rMove.Unit end; I_CamVel=I_CamVel:Lerp((camCF.LookVector*(-rMove.Y)+camCF.RightVector*rMove.X)*(FC.speed*60),math.clamp(sdt*3.5,0,1)); local hT=0; if fcKeysHeld[Enum.KeyCode.E] or FC_UI_Btns.up then hT=FC.speed*60 end; if fcKeysHeld[Enum.KeyCode.Q] or FC_UI_Btns.down then hT=-FC.speed*60 end; if hT==0 then heightVelocity=heightVelocity*math.max(0,1-sdt*10) else heightVelocity=heightVelocity+(hT-heightVelocity)*math.clamp(sdt*3,0,1) end; if FC_UI_Btns.zoomIn then Cam.FieldOfView=math.clamp(Cam.FieldOfView-1.2,10,120) end; if FC_UI_Btns.zoomOut then Cam.FieldOfView=math.clamp(Cam.FieldOfView+1.2,10,120) end; FC.pos=FC.pos+(I_CamVel+Vector3.new(0,heightVelocity,0))*sdt; Cam.CFrame=CFrame.new(FC.pos)*CFrame.Angles(0,math.rad(FC.yawDeg),0)*CFrame.Angles(math.rad(FC.pitchDeg),0,0)*CFrame.Angles(0,0,math.rad(FC.rollDeg)) end) end
