-- AUTO LIKE
local function getLikeRemotes() local r=ReplicatedStorage:FindFirstChild("Remotes"); if not r then return nil,nil end; return r:FindFirstChild("GetLikeDataRemote"),r:FindFirstChild("LikePlayerEvent") end
local function likeRandomPlayer() local _,lp=getLikeRemotes(); if not lp then return false,"Remote not found" end; local r=getRoot(); local t={}; for _,p in pairs(Players:GetPlayers()) do if p~=LP then if State.AutoLike.radius>0 and r then local pr=p.Character and p.Character:FindFirstChild("HumanoidRootPart"); if pr then local d=(pr.Position-r.Position).Magnitude; if d<=State.AutoLike.radius then table.insert(t,p) end end else table.insert(t,p) end end end; if #t==0 then return false,"No players in range" end; local target; if #t==1 then target=t[1] else repeat target=t[math.random(1,#t)] until target~=State.AutoLike.lastTarget or #t<=1 end; State.AutoLike.lastTarget=target; local s=pcall(function() lp:FireServer(target) end); if s then State.AutoLike.count=State.AutoLike.count+1; return true,target.DisplayName end; return false,"Failed" end
local function startAutoLike() if State.AutoLike.active then return end; State.AutoLike.active=true; State.AutoLike.thread=task.spawn(function() while State.AutoLike.active and getgenv()._XKID_RUNNING do local o,r=likeRandomPlayer(); if o then notify("Auto Like",r.." | Total: "..State.AutoLike.count,1.5,"heart") end; local cd=math.random(State.AutoLike.minCD*10,State.AutoLike.maxCD*10)/10; task.wait(cd) end; State.AutoLike.thread=nil end); notify("Auto Like","ON",2,"heart") end
local function stopAutoLike() State.AutoLike.active=false; if State.AutoLike.thread then task.cancel(State.AutoLike.thread); State.AutoLike.thread=nil end; notify("Auto Like","OFF",1.5,"heart") end

-- HARD FLING
local hardFlingConn,hardFlingRampConn,hardFlingBAV=nil,nil,nil
local function startHardFling() if State.HardFling.active then return end; State.HardFling.active=true; State.Move.ncp=true; State.HardFling.currentPower=0; State.HardFling.rampUpActive=true; local r=getRoot(); if r then hardFlingBAV=Instance.new("BodyAngularVelocity",r); hardFlingBAV.MaxTorque=Vector3.new(9e9,9e9,9e9); hardFlingBAV.P=100000 end; local rampStart=tick(); hardFlingRampConn=TrackC(RS.Heartbeat:Connect(function() if not State.HardFling.rampUpActive then return end; local t=math.clamp((tick()-rampStart)/2,0,1); State.HardFling.currentPower=State.HardFling.power*t; if t>=1 then State.HardFling.currentPower=State.HardFling.power; State.HardFling.rampUpActive=false end end)); hardFlingConn=TrackC(RS.Heartbeat:Connect(function() if not State.HardFling.active then return end; local r2=getRoot(); if not r2 then return end; if State.HardFling.mode=="Spin" then if hardFlingBAV and hardFlingBAV.Parent then hardFlingBAV.AngularVelocity=Vector3.new(0,State.HardFling.currentPower,0) end elseif State.HardFling.mode=="Shake" then if hardFlingBAV and hardFlingBAV.Parent then local sx=(math.random()-0.5)*State.HardFling.currentPower*0.5; local sy=(math.random()-0.5)*State.HardFling.currentPower*0.3; local sz=(math.random()-0.5)*State.HardFling.currentPower*0.5; hardFlingBAV.AngularVelocity=Vector3.new(sx,sy,sz) end end; if LP.Character then for _,p in pairs(LP.Character:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide=false end end end end)); notify("Hard Fling","ON — "..State.HardFling.mode,2,"zap") end
local function stopHardFling() State.HardFling.active=false; State.HardFling.rampUpActive=false; State.HardFling.currentPower=0; if hardFlingConn then hardFlingConn:Disconnect(); hardFlingConn=nil end; if hardFlingRampConn then hardFlingRampConn:Disconnect(); hardFlingRampConn=nil end; if hardFlingBAV then hardFlingBAV:Destroy(); hardFlingBAV=nil end; local r=getRoot(); if r then pcall(function() r.AssemblyAngularVelocity=Vector3.zero; r.AssemblyLinearVelocity=Vector3.zero end) end; if LP.Character then for _,p in pairs(LP.Character:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide=true end end end; notify("Hard Fling","OFF",1.5,"zap") end

