local function resetFilterOnly() for _,v in pairs(Lighting:GetChildren()) do if v.Name=="_XKID_FILTER" then v:Destroy() end end end
local function resetDOFOnly() for _,v in pairs(Lighting:GetChildren()) do if v.Name=="_XKID_DOF" then v:Destroy() end end end
local function applyCustomFilter() resetFilterOnly(); Lighting.Brightness=originalLighting.Brightness; Lighting.Ambient=originalLighting.Ambient; Lighting.OutdoorAmbient=originalLighting.OutdoorAmbient; Lighting.GlobalShadows=originalLighting.GlobalShadows; Lighting.ExposureCompensation=State.CustomFilter.exposure; local cc=Instance.new("ColorCorrectionEffect",Lighting); cc.Name="_XKID_FILTER"; cc.TintColor=Color3.fromRGB(State.CustomFilter.tintR,State.CustomFilter.tintG,State.CustomFilter.tintB); cc.Saturation=State.CustomFilter.saturation; cc.Contrast=State.CustomFilter.contrast; cc.Brightness=State.CustomFilter.brightness; local bloom=Instance.new("BloomEffect",Lighting); bloom.Name="_XKID_FILTER"; bloom.Intensity=State.CustomFilter.bloomIntensity; bloom.Size=State.CustomFilter.bloomSize; Lighting.ClockTime=State.CustomFilter.clockTime; resetDOFOnly(); if State.CustomFilter.dofIntensity>0 then local dof=Instance.new("DepthOfFieldEffect",Lighting); dof.Name="_XKID_DOF"; dof.FarIntensity=State.CustomFilter.dofIntensity; dof.FocusDistance=State.CustomFilter.dofDistance end end
local function applyFilter(f)
  resetFilterOnly(); resetDOFOnly(); Lighting.ClockTime=originalLighting.ClockTime; Lighting.Brightness=originalLighting.Brightness; Lighting.Ambient=originalLighting.Ambient; Lighting.OutdoorAmbient=originalLighting.OutdoorAmbient; Lighting.GlobalShadows=originalLighting.GlobalShadows; Lighting.ExposureCompensation=originalLighting.ExposureCompensation
  if f=="Default" then for k,v in pairs(FILTERS.Default) do if State.CustomFilter[k]~=nil then State.CustomFilter[k]=v end end; notify("Visuals","Default",1.5,"palette") return end
  if f=="Custom" then applyCustomFilter(); notify("Visuals","Custom FX",1.5,"palette") return end
  local key=f:gsub(" ","_"):gsub(" HD","_HD"); local p=FILTERS[key]
  if p then
    Lighting.ClockTime=p.time or 14; Lighting.Brightness=p.lightB or 1; Lighting.ExposureCompensation=p.exp or 0; Lighting.GlobalShadows=p.shadow~=false
    if p.ambient then Lighting.Ambient=p.ambient end; if p.outdoor then Lighting.OutdoorAmbient=p.outdoor end
    local cc=Instance.new("ColorCorrectionEffect",Lighting); cc.Name="_XKID_FILTER"; cc.TintColor=p.tint; cc.Saturation=p.sat or 0; cc.Contrast=p.con or 0; cc.Brightness=p.bri or 0
    local bloom=Instance.new("BloomEffect",Lighting); bloom.Name="_XKID_FILTER"; bloom.Intensity=p.bloomI or 0; bloom.Size=p.bloomS or 24
    if p.dofI and p.dofI>0 then local dof=Instance.new("DepthOfFieldEffect",Lighting); dof.Name="_XKID_DOF"; dof.FarIntensity=p.dofI; dof.FocusDistance=p.dofD or 50 end
    State.CustomFilter.tintR=p.tint.R*255; State.CustomFilter.tintG=p.tint.G*255; State.CustomFilter.tintB=p.tint.B*255; State.CustomFilter.saturation=p.sat or 0; State.CustomFilter.contrast=p.con or 0; State.CustomFilter.brightness=p.bri or 0; State.CustomFilter.exposure=p.exp or 0; State.CustomFilter.bloomIntensity=p.bloomI or 0; State.CustomFilter.bloomSize=p.bloomS or 24; State.CustomFilter.clockTime=p.time or 14; State.CustomFilter.dofIntensity=p.dofI or 0; State.CustomFilter.dofDistance=p.dofD or 50
    notify("Visuals",f,2,"palette")
  end
end

