local secChat = TabLog:Section({Title="Chat Logger",Icon="message-square",Box=true})
secChat:Toggle({Title="Enable Logger",Default=false,Callback=function(v) State.Utility.chatLog=v; if not v then pcall(function() chatLogPanel:SetDesc("Logger disabled") end) end; notify("Logger",v and "ON" or "OFF",1.5,"terminal") end})
chatTargetLabel = secChat:Paragraph({Title="Targets",Desc="None"})
chatTargetDrop = secChat:Dropdown({Title="Select Targets",Multi=true,AllowNone=true,Values=getDisplayNames(),Callback=function(s) State.Utility.chatTargets={}; if s and typeof(s)=="table" then for _,n in ipairs(s) do table.insert(State.Utility.chatTargets,tostring(n)) end end; if #State.Utility.chatTargets>0 then pcall(function() chatTargetLabel:SetDesc("Tracking: "..table.concat(State.Utility.chatTargets,", ")) end) else pcall(function() chatTargetLabel:SetDesc("None") end) end end})
secChat:Button({Title="Clear Targets",Callback=function() State.Utility.chatTargets={}; pcall(function() chatTargetLabel:SetDesc("None") end); pcall(function() chatTargetDrop:SetValues({}); task.wait(0.05); chatTargetDrop:SetValues(getDisplayNames()) end); notify("Logger","Targets cleared",1.5,"terminal") end})
secChat:Button({Title="Refresh List",Callback=function() pcall(function() chatTargetDrop:Refresh(getDisplayNames(),true) end); notify("Logger","List refreshed",1.5,"terminal") end})
chatLogPanel = secChat:Paragraph({Title="Console",Desc="Belum ada chat..."})
secChat:Button({Title="Clear Log",Callback=function() State.Utility.chatHistory={}; pcall(function() chatLogPanel:SetDesc("Belum ada chat...") end); notify("Logger","Log cleared",1.5,"terminal") end})
task.spawn(function() local function onChat(sn,msg) if not State.Utility.chatLog or #State.Utility.chatTargets==0 then return end; local cs=sn:lower():match("^%s*(.-)%s*$"); for _,t in ipairs(State.Utility.chatTargets) do local ct=t:lower():match("^%s*(.-)%s*$"); if cs==ct then local e=string.format("[%s] %s: %s",os.date("%H:%M:%S"),sn,msg); table.insert(State.Utility.chatHistory,e); if #State.Utility.chatHistory>50 then table.remove(State.Utility.chatHistory,1) end; notify("Chat",sn..": "..msg,2,"message-circle"); break end end end; if TextChatService.ChatVersion==Enum.ChatVersion.TextChatService then pcall(function() TrackC(TextChatService.MessageReceived:Connect(function(m) if m.TextSource then onChat(m.TextSource.Name,m.Text) end end)) end) end; local function connectLegacy(p) pcall(function() TrackC(p.Chatted:Connect(function(m) onChat(p.DisplayName,m) end)) end) end; for _,p in pairs(Players:GetPlayers()) do if p~=LP then connectLegacy(p) end end; TrackC(Players.PlayerAdded:Connect(function(p) if p~=LP then connectLegacy(p) end end)) end)
task.spawn(function() while getgenv()._XKID_RUNNING do task.wait(0.5); if chatLogPanel and State.Utility.chatLog then pcall(function() local t=table.concat(State.Utility.chatHistory,"\n"); if #t>2000 then t=t:sub(-2000) end; if #t==0 then t="Belum ada chat..." end; chatLogPanel:SetDesc(t) end) end end end)

